external_knowledge:
- 'More mature folks' refers to individuals whose age is greater than the average age of all individuals in the demographic data;
- The net income is calculated as the difference between capital gains and capital losses;
- The average net income must be considered only if it is greater than 30,000 for a relationship status to be included in the results.

sql:
SELECT person_id, age
FROM demographic_data
WHERE age > 30;

SELECT AVG(age) AS avg_age
FROM demographic_data
WHERE salary_id > (
  SELECT AVG(salary_id)
  FROM demographic_data
);

SELECT person_id, age, capital_gain, capital_loss, workclass_id, education_id, maritalstatus_id, occupation_id, relationship_id, race_id, sex_id, hours_per_week, native_country_id, salary_id, date_of_birth, employment_status, disability_status, veteran_status, citizenship_status, last_updated, data_source
FROM demographic_data
WHERE capital_gain = (SELECT MAX(capital_gain) FROM demographic_data);

SELECT access_id
FROM access_logs
WHERE access_id BETWEEN 5 AND 10;

SELECT COUNT(DISTINCT person_id) AS 'Number of People'
FROM demographic_data
WHERE age >= 18 
  AND workclass_id IN (
    SELECT workclass_id FROM workclasses WHERE is_government = 1
  ) 
  AND education_id IN (
    SELECT education_id FROM educations WHERE degree_type IN ('Bachelor', 'Master')
  ) 
  AND maritalstatus_id IN (
    SELECT maritalstatus_id FROM maritalstatuses WHERE is_married = 1
  ) 
  AND occupation_id IN (
    SELECT occupation_id FROM occupations WHERE industry = 'Technology'
  ) 
  AND relationship_id IN (
    SELECT relationship_id FROM relationships WHERE is_head_of_household = 1
  ) 
  AND race_id IN (
    SELECT race_id FROM races WHERE race_name IN ('White', 'Asian')
  ) 
  AND sex_id IN (
    SELECT sex_id FROM sexes WHERE gender_identification = 'Female'
  ) 
  AND native_country_id IN (
    SELECT native_country_id FROM native_countries WHERE continent = 'North America'
  ) 
  AND salary_id IN (
    SELECT salary_id FROM salaries WHERE salary_bracket = 'Middle'
  ) 
  AND hours_per_week >= 40;
